module ripple_carry_adder(
    input [3:0] A, 
    input [3:0] B, 
    output [4:0] S
);
    wire [3:0] overflow;

    assign S[0] = A[0] ^ B[0];
    assign overflow[0] = A[0] & B[0];

    assign S[1] = A[1] ^ B[1] ^ overflow[0];
    assign overflow[1] = (A[1] & B[1]) | (overflow[0] & (A[1] ^ B[1]));

    assign S[2] = A[2] ^ B[2] ^ overflow[1];
    assign overflow[2] = (A[2] & B[2]) | (overflow[1] & (A[2] ^ B[2]));

    assign S[3] = A[3] ^ B[3] ^ overflow[2];
    assign overflow[3] = (A[3] & B[3]) | (overflow[2] & (A[3] ^ B[3]));

    assign S[4] = overflow[3];

endmodule
